using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9: Migrate() now manages its own transactions and ExecutionStrategy.
    // Wrapping it in a user transaction throws at runtime.
    void ApplyMigrations(AppDbContext db)
    {
        db.Database.Migrate();
    }
}

